1	const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
2	
3	function validateItemTypes(items: any[]): void {
4	  for (const item of items) {
5	    if (!KNOWN_TYPES.includes(item.type)) {
6	      throw new Error(`Unknown item type: ${item.type}`);
7	    }
8	  }
9	}
10	
11	const INSURANCE_VALUES: Record<string, number> = {
12	  sword: 1000,
13	  amulet: 600,
14	  staff: 800,
15	  potion: 400,
16	  rune: 250,
17	  moonstone: 250,
18	};
19	
20	const DEDUCTIBLE = 100;
21	
22	const PROCESSING_FEE = 5;
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	function basePremium(item: any): number {
34	  return BASE_PREMIUMS[item.type] ?? 0;
35	}
36	
37	const COMPONENT_TYPES = ["rune", "moonstone"];
38	const BLOCK_SIZE = 3;
39	const BLOCK_PREMIUM = 60;
40	
41	function isComponent(item: any): boolean {
42	  return COMPONENT_TYPES.includes(item.type);
43	}
44	
45	function groupByType(items: any[]): Record<string, any[]> {
46	  const result: Record<string, any[]> = {};
47	  for (const item of items) {
48	    if (!result[item.type]) result[item.type] = [];
49	    result[item.type].push(item);
50	  }
51	  return result;
52	}
53	
54	function componentGroupPremium(group: any[]): number {
55	  if (group.length === BLOCK_SIZE) return BLOCK_PREMIUM;
56	  return group.reduce((sum: number, item: any) => sum + basePremium(item), 0);
57	}
58	
59	export function claimOffice(input: any): unknown {
60	  const results = [];
61	  const quoteSteps: any[] = [];
62	  let quoteCount = 0;
63	  for (const step of input.steps) {
64	    if (step.op === "claim") {
65	      const policyItems = quoteSteps[step.policy];
66	
67	      const damageCounts: Record<string, number> = {};
68	      for (const damage of step.incident.damages) {
69	        damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
70	      }
71	      const policyCounts: Record<string, number> = {};
72	      for (const item of policyItems) {
73	        policyCounts[item.type] = (policyCounts[item.type] ?? 0) + 1;
74	      }
75	      for (const [type, count] of Object.entries(damageCounts)) {
76	        if (count > (policyCounts[type] ?? 0)) {
77	          throw new Error(`Damages exceed policy coverage for type: ${type}`);
78	        }
79	      }
80	
81	      const insuranceSum = policyItems.reduce(
82	        (sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? 0),
83	        0
84	      );
85	      const cap = 2 * insuranceSum;
86	      let payout = 0;
87	      for (const damage of step.incident.damages) {
88	        const matchingItem = policyItems.find((item: any) => item.type === damage.itemType);
89	        let reimbursement = damage.amount;
90	        if (matchingItem && matchingItem.enchantment >= 8) {
91	          reimbursement = damage.amount * 0.5;
92	        }
93	        payout += reimbursement - DEDUCTIBLE;
94	      }
95	      const remainingCap = cap - payout;
96	      results.push({ payout, remainingCap });
97	      continue;
98	    }
99	
100	    quoteSteps.push(step.items);
101	
102	    validateItemTypes(step.items);
103	
104	    const components = step.items.filter(isComponent);
105	    const nonComponents = step.items.filter((i: any) => !isComponent(i));
106	
107	    let rawPolicyBase = 0;
108	    let itemSpecificSurcharges = 0;
109	
110	    for (const item of nonComponents) {
111	      const base = basePremium(item);
112	      rawPolicyBase += base;
113	      if (item.cursed) {
114	        itemSpecificSurcharges += base * 0.5;
115	      }
116	      if (item.enchantment >= 5) {
117	        itemSpecificSurcharges += base * 0.3;
118	      }
119	    }
120	
121	    for (const group of Object.values(groupByType(components))) {
122	      rawPolicyBase += componentGroupPremium(group);
123	    }
124	
125	    let policyWideModifier = 0;
126	
127	    // First insurance surcharge: 10% of policy base premium (always applies)
128	    policyWideModifier += rawPolicyBase * 0.1;
129	
130	    if (input.customer.yearsWithMHPCO >= 2) {
131	      policyWideModifier -= rawPolicyBase * 0.2;
132	    }
133	
134	    quoteCount++;
135	    if (quoteCount > 1) {
136	      policyWideModifier -= rawPolicyBase * 0.15;
137	    }
138	
139	    const premium = Math.ceil(rawPolicyBase + itemSpecificSurcharges + policyWideModifier + PROCESSING_FEE);
140	
141	    results.push({ premium });
142	  }
143	  return { results };
144	}
